1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Customer = { yearsWithMHPCO: number };
10	
11	export type Scenario = {
12	  customer: Customer;
13	  steps: QuoteStep[];
14	};
15	
16	export type ScenarioResult = {
17	  results: unknown[];
18	};
19	
20	const COMPONENT_BASE_PREMIUM = 25;
21	
22	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: COMPONENT_BASE_PREMIUM,
28	  moonstone: COMPONENT_BASE_PREMIUM,
29	};
30	
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
32	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const LOYALTY_THRESHOLD_YEARS = 2;
35	const PROCESSING_FEE = 5;
36	
37	const CURSED_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	
41	function isCursed(item: Item): boolean {
42	  return item.cursed === true;
43	}
44	
45	function isHighlyEnchanted(item: Item): boolean {
46	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	}
48	
49	function riskMultiplierForItem(item: Item): number {
50	  return (
51	    1 +
52	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
53	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
54	  );
55	}
56	
57	function basePremiumForItem(item: Item): number {
58	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
59	}
60	
61	type QuoteResult = { kind: "quote"; premium: number };
62	
63	const BUILDING_BLOCK_BASE_PREMIUM = 60;
64	const BUILDING_BLOCK_SIZE = 3;
65	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
66	
67	type ItemGroup = { kind: Item["kind"]; items: Item[] };
68	
69	function groupByKind(items: Item[]): ItemGroup[] {
70	  const groups = new Map<Item["kind"], Item[]>();
71	  for (const item of items) {
72	    const group = groups.get(item.kind) ?? [];
73	    group.push(item);
74	    groups.set(item.kind, group);
75	  }
76	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
77	}
78	
79	function isComponentKind(kind: Item["kind"]): boolean {
80	  return COMPONENT_KINDS.includes(kind);
81	}
82	
83	function isBuildingBlock(group: ItemGroup): boolean {
84	  return group.items.length === BUILDING_BLOCK_SIZE && isComponentKind(group.kind);
85	}
86	
87	function basePremiumForGroup(group: ItemGroup): number {
88	  if (isBuildingBlock(group)) {
89	    return BUILDING_BLOCK_BASE_PREMIUM;
90	  }
91	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
92	}
93	
94	function basePremiumForItems(items: Item[]): number {
95	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
96	}
97	
98	function contractSequenceRate(contractIndex: number): number {
99	  return contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
100	}
101	
102	function loyaltyRate(customer: Customer): number {
103	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
104	}
105	
106	function customerRateForContract(
107	  contractIndex: number,
108	  customer: Customer,
109	): number {
110	  return contractSequenceRate(contractIndex) + loyaltyRate(customer);
111	}
112	
113	function quoteStep(
114	  step: QuoteStep,
115	  contractIndex: number,
116	  customer: Customer,
117	): QuoteResult {
118	  const basePremium = basePremiumForItems(step.items);
119	  const customerAdjustment = basePremium * customerRateForContract(contractIndex, customer);
120	  const premium = Math.ceil(basePremium + customerAdjustment + PROCESSING_FEE);
121	  return { kind: "quote", premium };
122	}
123	
124	export function processScenario(scenario: Scenario): ScenarioResult {
125	  const results = scenario.steps.map((step, index) => quoteStep(step, index, scenario.customer));
126	  return { results };
127	}
